#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for UBNT/UniFi 企业 Wi-Fi 工程.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="UBNT/UniFi 企业 Wi-Fi 工程"
DIM_COUNT=6

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (6 个):
  9.1 场景容量诊断 (Scene capacity diagnostic)
  9.2 症状指标定位 (Symptom diagnostic — retry / MCS / channel utilization NOT RSSI)
  9.3 客户端兼容性 audit (Client compatibility audit)
  9.4 CCI / ACI / 频谱审视 (Channel plan health)
  9.5 CVE / 协议安全 advisory check (Security posture)
  9.6 Vendor 对比锚 (Cross-vendor benchmark)

背后的心智模型:
  • 容量优先, 覆盖次之 (Capacity-first, coverage second): 80 人密集办公的 Wi-Fi 瓶颈不是覆盖, 是同信道干扰 (CCI) — 加 AP 反而让网络更慢; 工程师先算 airtime budget, 后摆 AP.
  • Retry rate > RSSI (重试率比信号强度更能定位问题): 客户跟你说 "信号差", 你先要 retry % 和 channel utilization, 不要 RSSI — RSSI 满格但 retry 30% (业内估计 — CCI 阈值) 是 CCI /
  • RF 物理是 vendor-neutral 基础 (放大版心智模型 — V3 PARTIAL): 「学了 RF 物理 + 802.11 协议, 你换 Cisco / Aruba / Mist / UniFi 任何一家都活得下来; 反过来只会 UniFi GUI 不是 Wi-Fi 工程师, 是 GU

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "场景容量诊断 (Scene capacity diagnostic)"
  "症状指标定位 (Symptom diagnostic — retry / MCS / channel utilization NOT RSSI)"
  "客户端兼容性 audit (Client compatibility audit)"
  "CCI / ACI / 频谱审视 (Channel plan health)"
  "CVE / 协议安全 advisory check (Security posture)"
  "Vendor 对比锚 (Cross-vendor benchmark)"
)
declare -a DIM_QUESTIONS=(
  "并发活跃客户端数 (= 人数 × 1.5-2 设备 × 30-50% 并发因子 — 业内估计, T01-S007 vonNagy + T04-CWDP 公开方法), per-client 吞吐需求 (办公典型 25 Mbps; voice 1 Mbps + latency SLA; engineering 50-100 Mbps — 业内估计, CWAP-404 教材), 当前每 AP airtime utilization (target < 60% 工作时段 — 业内估计, vonNagy SLO 公开 baseline)"
  "客户端 retry % (target < 5%, alarm > 15% — 业内估计, T01-S007 vonNagy + T01-S015 Mackenzie 公开 messaging), MCS distribution (是否退到低 MCS), per-AP channel utilization (target < 60% — 业内估计, T04-CWAP SLO baseline), Tx error rate; **NOT** \"信号格\" / RSSI alone"
  "OS 分布 (iOS / Android / Win / macOS / IoT) + 主要型号; Wi-Fi 代际支持 (Wi-Fi 4/5/6/6E/7) + chipset; 11k/v/r 支持状态 (注意老 Android 11r 易破); WPA3 支持; MLO 支持 (Wi-Fi 7 only); 客户端 Tx power 范围 (typical 14-18 dBm)"
  "同信道 AP 数 (邻居 BSSID 计数 in 周围 -85 dBm 以内 CCA 范围); 信道宽度选择 (5GHz 80/40/20 MHz tradeoff); 2.4 GHz 是否启用 (典型 disable on 大多数 AP); DFS 信道使用率; non-Wi-Fi 干扰源 (微波炉 / 蓝牙 / cordless / 雷达)"
  "当前 UniFi Network App 版本 + AP firmware 版本; 与最新 release 的差 + CVE 累积; WPA3 / PMF Mandatory / SAE-PT 状态; FragAttacks vendor patch 状态; 历史 KRACK / Dragonblood patch 完整性"
  "客户是否提及 Mist (Marvis AI) / Meraki (cloud) / Aruba Central / Cisco WLC / Ruijie / Omada 等对比; 在客户语境下哪个 dimension 是 deal-breaker (AI ops? 成本? 自管控制权? 全球分布?); UBNT 的相对强弱在该 dimension"
)
declare -a DIM_SOURCES=(
  "UniFi controller Insights → Client Count + Airtime → CSV export; iFeelTech 5-15 / 15-40 / 40-75+ blueprint 模板 (T05-S023); vonNagy capacity-first spreadsheet (Revolution Wi-Fi); Ekahau / Hamina predictive design"
  "UniFi controller → Insights / Events; Wireshark + airmon-ng / Airtool 2 (macOS) capture at the client's desk (not at AP); WiFi Explorer Pro (macOS) / inSSIDer (Win) for channel utilization view; WLAN Pi remote capture"
  "UniFi controller → Clients → device fingerprint; MDM (Intune / JAMF) device inventory; Apple Wi-Fi roaming doc + Microsoft Learn 11k/v/r ref (T03-S020); CWNP 11k/v/r explainer (T03-S019); 已知 IoT 兼容性 list (Sonos / Apple HomeKit / Google Cast)"
  "WiFiman + 走动 (装机后); WiFi Explorer Pro (macOS) 看 channel utilization; MetaGeek inSSIDer + Chanalyzer + Wi-Spy DBx (PHY 层频谱看非 Wi-Fi 源); UniFi controller → RF Environment heatmap; Willie Howe Channel Map (T03-S007) 作 5GHz 信道规划 quick reference"
  "blog.ui.com 官方 release notes; community.ui.com → Security advisories; Lawrence Systems VLOG (\"X Critical UniFi CVEs\"); Wi-Fi Alliance security spec hub (T03-S030); Vanhoef sites (krackattacks.com, wpa3.mathyvanhoef.com, fragattacks.com)"
  "客户对话 transcript / RFP 文本; Mist blog (T05-S025) 看 AIOps 当前 frontier; MFD14 (May 2026) presentations 看 vendor 比较 (Ubiquiti 返回 MFD14 是重要信号 — T05-S011); Heavy Wireless eps critique Mist (T05-S007); iFeelTech TCO blueprints (T05-S023)"
)
declare -a DIM_OUTPUT_FORMATS=(
  "结构化 → \`客户端密度: {N 人 × M 设备 × P% 并发 = K active radios}; 每 AP 容量: {100-200 Mbps × 30-60% 效率 = Q Mbps (业内估计 — T01-S007 vonNagy/T04-CWDP 公开公式)} ; 推荐 AP 数: {K / (Q ÷ per-client SLA) × 1.5 safety = R 个}; 与现有部署 gap: {±X 个}\`"
  "结构化 → \`症状层级 (PHY/MAC/assoc/auth/IP): {层}; retry %: {N% — 健康/亚健康/失败}; MCS: {高/中/低 — 是否退到 802.11g 速率}; channel utilization: {N%}; SNR: {N dB at client desk}; 假设根因: {CCI/noise/client driver/auth retry}\`"
  "结构化 → \`客户端总数: {N}; Wi-Fi 代际分布: {ax:N1%, ac:N2%, n:N3%}; 11r 安全启用: {是/否, 风险设备 list}; WPA3 兼容: {N% 现代 + IoT 排他 SSID 计划}; 弱设备约束: {最差 Tx power / 最差 chipset 限制设计上限}\`"
  "结构化 → \`共信道 AP 计数: {N (target ≤ 3 在 5 GHz)}; 信道宽度: {推荐 5 GHz 40 MHz dense / 80 MHz sparse, 2.4 GHz 20 MHz only}; DFS 信道启用: {是/否, 雷达检测频率}; 非 Wi-Fi 干扰: {蓝牙/微波/雷达 — 频段 + 时段}; 信道重规划建议: {AP 1 → ch X, AP 2 → ch Y, ...}\`"
  "结构化 → \`当前版本: {Network App vX.Y, AP firmware vA.B}; 与最新 gap: {N versions behind}; 未 patch 的 CVE: {CVE-202X-XXXX list with severity}; 协议层风险: {WPA2 fallback / PMF Optional / 11w 未 Mandatory}; 建议升级窗口: {immediate CVE-critical / next maintenance window feature-only}\`"
  "结构化 → \`客户对比的 vendor: {Mist / Meraki / Aruba / ...}; 客户在意 dimension: {AIOps / cloud / 成本 / 自管 / 全球}; UBNT 相对优势: {成本 5-10x 便宜 + 自管 controller + Hosted UniFi 选项}; UBNT 相对劣势: {AIOps 弱 + 大型企业 reference 案例少 + AIOps cert 体系 (JNCIS-MistAI) 不存在}; 妥协路径: {如客户坚持 AIOps → unifi-mcp + unpoller + Claude \"poor man's AIOps\", 但成本与体验差距 transparent 告知}\`"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
